<?php namespace App\Http\Middleware; use Closure; use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Facades\DB; use Symfony\Component\HttpFoundation\Response; class AuditLogMiddleware { public function handle(Request $request, Closure $next): Response { return $next($request); } public function terminate(Request $request, Response $response): void { if (in_array($request->method(), ['POST', 'PUT', 'PATCH', 'DELETE'])) { $this->logRequest($request, $response); } } protected function logRequest(Request $request, Response $response): void { DB::table('audit_logs')->insert([ 'user_id' => Auth::id(), 'url' => $request->fullUrl(), 'method' => $request->method(), 'ip_address' => $request->ip(), 'user_agent' => $request->userAgent(), 'payload' => json_encode($request->except(['password', 'password_confirmation'])), 'response_code' => $response->getStatusCode(), 'created_at' => now(), ]); } }